on_energy_payment(pokemon, required, current_energy):
    missing = required - current_energy
    if missing > 0:
        hp_cost = missing * 0.05 * pokemon.hp
        if pokemon.current_hp > hp_cost:
            pokemon.current_hp -= hp_cost
            return required  # 支付成功
        else:
            return -1  # 无法支付

on_use_skill(user, skill):
    if skill.skill_type == WATER:
        for s in user.skills:
            s.energy_cost = max(0, s.energy_cost - 1)

on_use_skill(user, skill):
    if skill.skill_type == GRASS:
        user.current_hp = min(user.hp, user.current_hp + 0.1 * user.hp)

modify_final_energy_cost(pokemon, skill, base_cost, modified_cost):
    if pokemon.has_ability('对流'):
        delta = modified_cost - base_cost
        return max(1, base_cost - delta)
    return modified_cost
